mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM resumes r
    JOIN personal_profiles pp ON pp.id = r.personal_profile_id
    WHERE pp.user_id = #{userId}
      AND r.id = #{resumeId}
      AND r.deleted_at IS NULL
)

SELECT EXISTS (
    SELECT 1
    FROM job_posts jp
    JOIN company_profiles cp ON cp.id = jp.company_profile_id
    WHERE cp.user_id = #{userId}
      AND jp.id = #{jobPostId}
      AND jp.deleted_at IS NULL
)
